import type { Metadata } from "next";
import GroundHandlingConsole from "./GroundHandlingConsole";

export const metadata: Metadata = {
  title: "ランプコントロール — グランドハンドリング当務コンソール | ぐんじょう 空港",
  description:
    "羽田空港 第2ターミナルのランプコントロール（ランプ管理 / グランドハンドリング）向け当務コンソール。トーイングトラクター・ベルトローダー・ハイリフト・GPU・PCA・PBB・カーゴドーリー等の地上支援機材（GSE）の配置と稼働/待機/故障/整備中/燃料低を状態盤で一覧監視。スポット駐機状況と機材（B787/A350/B737）・STA/STD・ターンアラウンドフェーズを把握し、到着→PBB装着→取卸→給油→機内清掃→ケータリング→搭載→旅客搭乗→プッシュバック→出発の作業進捗を予定/実績で追跡。OTPリスク・GSE故障・人員不足・ULD不足・給油遅れを要対応キューでトリアージし、当務引継ぎと安全2人確認を署名で確定する画面。",
};

export default function GroundHandlingPage() {
  return <GroundHandlingConsole />;
}

// 羽田空港 第2ターミナル ランプコントロール — グランドハンドリング実データ風モック
// すべてドメイン語彙（スポット / GSE / ターンアラウンド / OTP …）で構成。

export type GseKind =
  | "トーイングトラクター"
  | "ベルトローダー"
  | "ハイリフトローダー"
  | "GPU（地上電源）"
  | "PCA（空調）"
  | "PBB（搭乗橋）"
  | "カーゴドーリー"
  | "パッセンジャーステップ";

export type GseStatus = "稼働中" | "待機" | "故障" | "整備中" | "燃料低";

export interface GseUnit {
  id: string; // 機番（社内管理番号）
  kind: GseKind;
  /** 配置: スポット番号 / 待機エリア / 整備庫 */
  location: string;
  status: GseStatus;
  /** 割当便（稼働中のとき） */
  assignedFlight?: string;
  /** 補足（故障内容・燃料残・整備予定など） */
  note?: string;
}

export const GSE_FLEET: GseUnit[] = [
