  { id: "HL-02", kind: "ハイリフトローダー", location: "整備庫A", status: "整備中", note: "定期点検（6か月）〜13:00" },
  { id: "GPU-14", kind: "GPU（地上電源）", location: "スポット64", status: "稼働中", assignedFlight: "NH212" },
  { id: "GPU-08", kind: "GPU（地上電源）", location: "スポット15", status: "稼働中", assignedFlight: "NH642" },
  { id: "GPU-21", kind: "GPU（地上電源）", location: "待機エリアB", status: "故障", note: "出力不安定／要点検" },
  { id: "PCA-03", kind: "PCA（空調）", location: "スポット64", status: "稼働中", assignedFlight: "NH212" },
  { id: "PCA-06", kind: "PCA（空調）", location: "待機エリアB", status: "待機" },
  { id: "PBB-64", kind: "PBB（搭乗橋）", location: "スポット64", status: "稼働中", assignedFlight: "NH212", note: "L1ドア装着済" },
  { id: "PBB-15", kind: "PBB（搭乗橋）", location: "スポット15", status: "稼働中", assignedFlight: "NH642", note: "L1装着済" },
  { id: "PBB-58", kind: "PBB（搭乗橋）", location: "スポット58", status: "待機" },
