export const GSE_STATUS_TONE: Record<
  GseStatus,
  { badge: "success" | "secondary" | "destructive" | "warning" | "info"; meterTone: "success" | "muted" | "destructive" | "warning"; rank: number }
> = {
  故障: { badge: "destructive", meterTone: "destructive", rank: 0 },
  燃料低: { badge: "warning", meterTone: "warning", rank: 1 },
  整備中: { badge: "info", meterTone: "muted", rank: 2 },
  稼働中: { badge: "success", meterTone: "success", rank: 3 },
  待機: { badge: "secondary", meterTone: "muted", rank: 4 },
};

// ───────────────────────── スポット / 駐機状況 ─────────────────────────

export type SpotPhase =
  | "到着前"
  | "ターンアラウンド中"
  | "搭乗中"
  | "出発準備"
  | "出発済"
  | "沖止め";

export interface SpotRow {
  spot: string; // スポット番号
  aircraft: string; // 機材タイプ
  reg: string; // 機体記号 JA…
  flightIn?: string; // 到着便
  flightOut?: string; // 出発便
  sta?: string; // 到着STA
  std?: string; // 出発STD
  phase: SpotPhase;
  /** 出発予測 vs STD の遅延（分）。+遅延 / -前倒し */
  otpRiskMin: number;
}

export const SPOTS: SpotRow[] = [
  { spot: "64", aircraft: "B787-9", reg: "JA友890A", flightIn: "NH106", flightOut: "NH212", sta: "10:42", std: "12:05", phase: "ターンアラウンド中", otpRiskMin: 12 },
  { spot: "15", aircraft: "A350-900", reg: "JA友313A", flightIn: "NH642", flightOut: "NH643", sta: "10:58", std: "12:20", phase: "搭乗中", otpRiskMin: 0 },
  { spot: "58", aircraft: "B737-800", reg: "JA友556J", flightOut: "NH985", std: "11:50", phase: "出発準備", otpRiskMin: -3 },
  { spot: "202", aircraft: "A320neo", reg: "JA友221N", flightIn: "NH1881", flightOut: "NH1882", sta: "11:05", std: "12:35", phase: "沖止め", otpRiskMin: 8 },
  { spot: "63", aircraft: "B777-300ER", reg: "JA友773W", flightIn: "NH118", sta: "11:20", phase: "到着前", otpRiskMin: 0 },
