// ───────────────────── ターンアラウンド進捗（NH212 / スポット64） ─────────────────────
// RouteStops の status: pending=未着手 / current=進行中 / completed=完了 / failed=中断 / delayed=遅延

export type TurnTaskStatus = "completed" | "current" | "delayed" | "pending" | "failed";

export interface TurnTask {
  id: string;
  title: string;
  description?: string;
  status: TurnTaskStatus;
  plannedTime?: string; // 予定 HH:MM
  actualTime?: string; // 実績 HH:MM
  crew?: string; // 担当班
}

export const TURNAROUND_NH212: TurnTask[] = [
  { id: "arr", title: "到着・ブロックイン", description: "スポット64  オンブロック", status: "completed", plannedTime: "10:42", actualTime: "10:48", crew: "誘導 3班" },
  { id: "pbb", title: "PBB装着（L1）", description: "搭乗橋接続・ドアモード解除", status: "completed", plannedTime: "10:46", actualTime: "10:53", crew: "ランプ 1班" },
  { id: "unload", title: "取卸（ULD / バルク）", description: "前後貨物室・ULD×6＋バルク手荷物", status: "completed", plannedTime: "10:50", actualTime: "11:02", crew: "ランプ 2班" },
  { id: "fuel", title: "給油", description: "27,400 L 搭載予定", status: "delayed", plannedTime: "11:00", actualTime: "11:18", crew: "給油業者" },
  { id: "clean", title: "機内清掃", description: "客室・ギャレー・化粧室", status: "current", plannedTime: "11:10", crew: "清掃 4班" },
