  { id: "load", title: "搭載（ULD / コンテナ）", description: "ULD×6・カーゴドーリー DLY-31", status: "pending", plannedTime: "11:30", crew: "ランプ 2班" },
  { id: "board", title: "旅客搭乗", description: "335名・優先搭乗〜一般", status: "pending", plannedTime: "11:35", crew: "GH 旅客" },
  { id: "push", title: "プッシュバック", description: "TT-07 牽引・PBB離脱後", status: "pending", plannedTime: "12:00", crew: "ランプ 1班" },
  { id: "dep", title: "出発・ブロックアウト", description: "STD 12:05", status: "pending", plannedTime: "12:05", crew: "誘導 3班" },
