export const KPIS: Kpi[] = [
  { label: "稼働スポット", value: "5 / 8", hint: "うち沖止め 1" },
  { label: "本日のターンアラウンド", value: "23 便", hint: "完了 14 ・ 進行 5 ・ 予定 4" },
  { label: "遅延便", value: "3 便", change: "+1", trend: "up", tone: "negative", hint: "15分以上" },
