"use client";

import * as React from "react";
import {
  PageHeader,
  StatGroup,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Badge,
  Tag,
  Meter,
  Button,
  Separator,
  RouteStops,
  ActionQueue,
  SignedRecord,
  CoSign,
  StatusBar,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  type RouteStopItem,
  type RouteStopStatus,
  type ActionItem,
  type SignedRecordValue,
  type CoSignValue,
  type StatisticProps,
} from "@gunjo/ui";

import {
  GSE_FLEET,
  GSE_STATUS_TONE,
  type GseUnit,
  type GseKind,
  SPOTS,
  type SpotRow,
  type SpotPhase,
  TURNAROUND_NH212,
  RAMP_ACTIONS,
  KPIS,
} from "./data";

// ───────────────────────── Equipment / GSE status board ─────────────────────────
// No purpose-built "device status board" exists in the kit. Hand-rolled with
// Card + Badge + Meter + Tag, grouped by GSE kind, sorted so faults rise.

const GSE_KINDS: GseKind[] = [
  "PBB（搭乗橋）",
  "トーイングトラクター",
  "ベルトローダー",
  "ハイリフトローダー",
  "GPU（地上電源）",
  "PCA（空調）",
  "カーゴドーリー",
  "パッセンジャーステップ",
];

function GseUnitChip({ unit }: { unit: GseUnit }) {
  const tone = GSE_STATUS_TONE[unit.status];
  const down = unit.status === "故障" || unit.status === "燃料低";
  return (
    <li
      className={
        "flex flex-col gap-1 rounded-md border p-2.5 text-sm " +
        (down
          ? "border-destructive-border bg-destructive-subtle"
          : "border-border bg-card")
      }
    >
      <div className="flex items-center justify-between gap-2">
        <span className="font-semibold tabular-nums text-foreground">{unit.id}</span>
        <Badge variant={tone.badge}>{unit.status}</Badge>
      </div>
      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
        <span aria-hidden>📍</span>
        <span className="truncate">{unit.location}</span>
        {unit.assignedFlight ? (
          <Tag size="sm" variant="outline">
            {unit.assignedFlight}
          </Tag>
        ) : null}
      </div>
      {unit.note ? (
        <p className={"text-xs " + (down ? "text-destructive" : "text-muted-foreground")}>
          {unit.note}
        </p>
      ) : null}
    </li>
  );
}

function EquipmentBoard() {
  const down = GSE_FLEET.filter((u) => u.status === "故障" || u.status === "燃料低");
  const inMaint = GSE_FLEET.filter((u) => u.status === "整備中");
  const active = GSE_FLEET.filter((u) => u.status === "稼働中");
  const availPct = Math.round(((GSE_FLEET.length - down.length - inMaint.length) / GSE_FLEET.length) * 100);

  return (
    <Card>
      <CardHeader>
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div>
            <CardTitle as="h2">GSE 状態盤</CardTitle>
            <CardDescription>
              地上支援機材 {GSE_FLEET.length} 台 ・ 稼働 {active.length} ・ 要対応{" "}
              <span className="font-semibold text-destructive">{down.length}</span> ・ 整備 {inMaint.length}
            </CardDescription>
          </div>
          <div className="w-48">
            <Meter
              value={availPct}
              max={100}
              direction="fill-is-good"
              unit="%"
              label="GSE 可用率"
              size="sm"
            />
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        {GSE_KINDS.map((kind) => {
          const units = GSE_FLEET.filter((u) => u.kind === kind).sort(
            (a, b) => GSE_STATUS_TONE[a.status].rank - GSE_STATUS_TONE[b.status].rank
          );
          if (units.length === 0) return null;
          const kindDown = units.filter((u) => u.status === "故障" || u.status === "燃料低").length;
          return (
            <section key={kind} aria-label={kind}>
              <div className="mb-1.5 flex items-center gap-2">
                <h3 className="text-sm font-semibold text-foreground">{kind}</h3>
                <span className="text-xs text-muted-foreground">{units.length}台</span>
                {kindDown > 0 ? (
                  <Badge variant="destructive">要対応 {kindDown}</Badge>
                ) : null}
              </div>
              <ul className="grid grid-cols-2 gap-2 sm:grid-cols-3 lg:grid-cols-4">
                {units.map((u) => (
                  <GseUnitChip key={u.id} unit={u} />
                ))}
              </ul>
            </section>
          );
        })}
      </CardContent>
    </Card>
  );
}

// ───────────────────────── スポット / 駐機状況 ─────────────────────────

const PHASE_BADGE: Record<SpotPhase, "success" | "info" | "warning" | "secondary" | "outline"> = {
  到着前: "secondary",
  ターンアラウンド中: "info",
  搭乗中: "info",
  出発準備: "warning",
  出発済: "success",
  沖止め: "outline",
};

function otpBadge(min: number) {
  if (min >= 10) return <Badge variant="destructive">+{min}分 遅延見込</Badge>;
  if (min > 0) return <Badge variant="warning">+{min}分</Badge>;
  if (min < 0) return <Badge variant="success">{min}分 前倒し</Badge>;
  return <Badge variant="success">定時</Badge>;
}

function StandStatus({
  selected,
  onSelect,
}: {
  selected: string;
  onSelect: (spot: string) => void;
}) {
  return (
    <Card>
      <CardHeader>
        <CardTitle as="h2">スポット / 駐機状況</CardTitle>
        <CardDescription>第2ターミナル ・ 当務監視スポット</CardDescription>
      </CardHeader>
      <CardContent>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-border text-left text-xs text-muted-foreground">
                <th scope="col" className="py-2 pr-3 font-medium">スポット</th>
                <th scope="col" className="py-2 pr-3 font-medium">機材 / 機体記号</th>
                <th scope="col" className="py-2 pr-3 font-medium">到着 / 出発</th>
                <th scope="col" className="py-2 pr-3 font-medium">STA / STD</th>
                <th scope="col" className="py-2 pr-3 font-medium">フェーズ</th>
                <th scope="col" className="py-2 pr-3 font-medium">OTP</th>
              </tr>
            </thead>
            <tbody>
              {SPOTS.map((s: SpotRow) => {
                const isSel = s.spot === selected;
                return (
                  <tr
                    key={s.spot}
                    tabIndex={0}
                    aria-current={isSel ? "true" : undefined}
                    onClick={() => onSelect(s.spot)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter" || e.key === " ") {
                        e.preventDefault();
                        onSelect(s.spot);
                      }
                    }}
                    className={
                      "cursor-pointer border-b border-border/60 outline-none transition-colors focus-visible:ring-2 focus-visible:ring-ring " +
                      (isSel ? "bg-muted/60" : "hover:bg-muted/30")
                    }
                  >
                    <td className="py-2.5 pr-3 font-semibold tabular-nums">{s.spot}</td>
                    <td className="py-2.5 pr-3">
                      <div className="font-medium text-foreground">{s.aircraft}</div>
                      <div className="text-xs text-muted-foreground">{s.reg}</div>
                    </td>
                    <td className="py-2.5 pr-3 text-xs tabular-nums">
                      <div>{s.flightIn ? `着 ${s.flightIn}` : "—"}</div>
                      <div>{s.flightOut ? `発 ${s.flightOut}` : "—"}</div>
                    </td>
                    <td className="py-2.5 pr-3 text-xs tabular-nums text-muted-foreground">
                      <div>{s.sta ?? "—"}</div>
                      <div>{s.std ?? "—"}</div>
                    </td>
                    <td className="py-2.5 pr-3">
                      <Badge variant={PHASE_BADGE[s.phase]}>{s.phase}</Badge>
                    </td>
                    <td className="py-2.5 pr-3">{otpBadge(s.otpRiskMin)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </CardContent>
    </Card>
  );
}

// ───────────────────────── ターンアラウンド進捗 (RouteStops) ─────────────────────────

const TURN_STATUS_LABELS: Partial<Record<RouteStopStatus, string>> = {
  pending: "未着手",
  current: "進行中",
  completed: "完了",
  delayed: "遅延",
  failed: "中断",
};

function TurnaroundProgress() {
  const stops: RouteStopItem[] = TURNAROUND_NH212.map((t) => ({
    id: t.id,
    title: t.title,
    description: t.description,
